import boto3
import json
import os

def publish_user_data_to_sqs(user_data: dict, queue_url: str):
    """
    Publishes user data, including PII, to an AWS SQS queue.

    Args:
        user_data (dict): A dictionary containing user information,
                          which may include PII like 'email', 'phone_number', 'address'.
                          Example:
                          {
                              "user_id": "unique_user_id_123",
                              "name": "Alice Wonderland",
                              "email": "alice.w@example.com",
                              "phone_number": "+15551234567",
                              "address": {
                                  "street": "123 Rabbit Hole",
                                  "city": "Wonderland",
                                  "state": "CA",
                                  "zip_code": "90210"
                              },
                              "preferences": {"newsletter": True}
                          }
        queue_url (str): The URL of the SQS queue to which the message will be sent.
                         Example: "https://sqs.us-east-1.amazonaws.com/123456789012/MyPiiDataQueue"
    """
    sqs = boto3.client('sqs')

    try:
        # Convert the user data dictionary to a JSON string
        message_body = json.dumps(user_data)

        # Send the message to the SQS queue
        response = sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=message_body
        )

        print(f"Message published successfully. MessageId: {response.get('MessageId')}")
        return response

    except Exception as e:
        print(f"Error publishing message to SQS: {e}")
        raise

